/**
 * @private
 * Adding a priority sorting function for menus
 */
Ext.define('pimcore.menu.menu', {
    extend: 'Ext.menu.Menu',

    initComponent: function() {

        let me = this;
        let items = me.items;

        if(items) {
            me.items = Ext.Array.sort(items, pimcore.helpers.priorityCompare);
        }

        me.callParent();
    }
});




